      "path": "src/modules/projects/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const { ProjectExistsError } = require('../../lib/errors');

let projects = [];

function createProject(projectData) {
  const existingProject = projects.find(p => p.name === projectData.name);
  if (existingProject) {
    throw new ProjectExistsError();
  }
  const project = { id: randomUUID(), ...projectData };
  projects.push(project);
  return project;
}

function getAllProjects() {
  return projects;
}

function getProjectById(id) {
  const project = projects.find(p => p.id === id);
  if (!project) {
    throw new Error('Project not found');
  }
  return project;
}

module.exports = { createProject, getAllProjects, getProjectById };
