      "content": "const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');
const { MemberExistsError, ProjectNotFoundError } = require('../../lib/errors');

let members = [];

function addMember(projectId, memberData) {
  const project = projectsService.getProjectById(projectId);
  if (!project) {
    throw new ProjectNotFoundError();
  }
  const existingMember = members.find(m => m.projectId === projectId && m.userId === memberData.userId);
  if (existingMember) {
    throw new MemberExistsError();
  }
  const member = { id: randomUUID(), projectId, ...memberData };
  members.push(member);
  return member;
}

function getAllMembers(projectId) {
  return members.filter(m => m.projectId === projectId);
}

module.exports = { addMember, getAllMembers };
