      "path": "src/modules/tasks/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');
const { ProjectNotFoundError, TaskNotFoundError } = require('../../lib/errors');

let tasks = [];

function createTask(projectId, taskData) {
  const project = projectsService.getProjectById(projectId);
  if (!project) {
    throw new ProjectNotFoundError();
  }
  const task = { id: randomUUID(), projectId, ...taskData };
  tasks.push(task);
  return task;
}

function getAllTasks(projectId, status) {
  let projectTasks = tasks.filter(t => t.projectId === projectId);
  if (status) {
    projectTasks = projectTasks.filter(t => t.status === status);
  }
  return projectTasks;
}

function updateTask(projectId, taskId, taskData) {
  const taskIndex = tasks.findIndex(t => t.id === taskId && t.projectId === projectId);
  if (taskIndex === -1) {
    throw new TaskNotFoundError();
  }
  tasks[taskIndex] = { ...tasks[taskIndex], ...taskData };
  return tasks[taskIndex];
}

module.exports = { createTask, getAllTasks, updateTask };
