const tasksService = require('../tasks/service');
const { TaskNotFoundError, ProjectNotFoundError } = require('../../lib/errors');

let comments = [];

function addComment(projectId, taskId, commentData) {
  const task = tasksService.getTaskById(taskId);
  if (!task || task.projectId !== projectId) {
    throw new TaskNotFoundError();
  }
  const comment = { id: randomUUID(), taskId, ...commentData };
  comments.push(comment);
  return comment;
}

function getAllComments(projectId, taskId) {
  return comments.filter(c => c.taskId === taskId);
}

module.exports = { addComment, getAllComments };
