  constructor() {
    super('Project already exists');
    this.statusCode = 409;
  }
}

class MemberExistsError extends Error {
  constructor() {
    super('Member already exists in the project');
    this.statusCode = 409;
  }
}

class ProjectNotFoundError extends Error {
  constructor() {
    super('Project not found');
    this.statusCode = 404;
  }
}

class TaskNotFoundError extends Error {
  constructor() {
    super('Task not found');
    this.statusCode = 404;
  }
}

function errorHandler(res, error) {
  res.status(error.statusCode || 500).json({ message: error.message });
}

module.exports = { ProjectExistsError, MemberExistsError, ProjectNotFoundError, TaskNotFoundError, errorHandler };
